// Take all rows from the Data Table and pack them into one object
const items = $input.all();

// Map to a cleaner structure (only fields we care about)
const orders = items.map(item => {
  const r = item.json;
  return {
    order_reference: r.Order_Reference,
    customer: r.Customer,
    order_date: r.Order_Date,
    expiration: r.Expiration,
    payment_terms: r.Payment_Terms,
    products: (r.OrderLinesProducts || "")
      .toString()
      .split(",")
      .map(p => p.trim())
      .filter(Boolean),
    quantity: Number((r.OrderLinesQuantity || "0").toString().replace(",", "")),
    unit_price: Number((r.OrderLinesUnitPrice || "0").toString().replace(",", "")),
    sales_team: r.Sales_Team,
    customer_reference: r.Customer_Reference,
    tags: (r.Tags || "")
      .toString()
      .split(",")
      .map(t => t.trim())
      .filter(Boolean),
  };
});

// Return ONE item with all orders inside
return [
  {
    json: {
      orders,
    },
  },
];
